    template <typename T>
    static inline T ppoly_race_kappa_d3(const T& s) {
        return ppoly_eval<T, 594, 0>(s, ppoly_race_kappa_d3_breaks, ppoly_race_kappa_d3_coeffs);
    }

    template <typename T>
    static inline int callback_race_kappa_segment(const MSVec<T, NP>& p, const T& s) {
        const double sd = static_cast<double>(s);
        if (sd < static_cast<double>(p(P_CALLBACK_BREAKS))) {
            return 0;
        }
        if (sd >= static_cast<double>(p(P_CALLBACK_BREAKS + P_CALLBACK_WINDOW_SEGMENTS))) {
            return P_CALLBACK_WINDOW_SEGMENTS - 1;
        }
        for (int i = 0; i < P_CALLBACK_WINDOW_SEGMENTS; ++i) {
            if (sd < static_cast<double>(p(P_CALLBACK_BREAKS + i + 1))) {
                return i;
            }
        }
        return P_CALLBACK_WINDOW_SEGMENTS - 1;
    }

    static inline int callback_race_kappa_coeff_offset(int segment) {
        return P_CALLBACK_COEFFS + 4 * segment;
    }

    template <typename T>
    static inline T callback_race_kappa(const MSVec<T, NP>& p, const T& s) {
        const int segment = callback_race_kappa_segment(p, s);
        const int offset = callback_race_kappa_coeff_offset(segment);
        const T ds = s - p(P_CALLBACK_BREAKS + segment);
        T y = p(offset + 0);
        y = y * ds + p(offset + 1);
        y = y * ds + p(offset + 2);
        y = y * ds + p(offset + 3);
        return y;
    }

    template <typename T>
    static inline T callback_race_kappa_d1(const MSVec<T, NP>& p, const T& s) {
        const int segment = callback_race_kappa_segment(p, s);
        const int offset = callback_race_kappa_coeff_offset(segment);
        const T ds = s - p(P_CALLBACK_BREAKS + segment);
        return (T(3.0) * p(offset + 0) * ds + T(2.0) * p(offset + 1)) * ds + p(offset + 2);
    }


    // --- Continuous Dynamics + Jacobians (Generated) ---
template<typename T>
    static void continuous_eval(
        const MSVec<T, NX>& x_in,
        const MSVec<T, NU>& u_in,
        const MSVec<T, NP>& p_in,
        MSVec<T, NX>& f_out,
        MSMat<T, NX, NX>& fx_out,
        MSMat<T, NX, NU>& fu_out)
    {
        T s = x_in(0);
        T n = x_in(1);
        T alpha = x_in(2);
        T v = x_in(3);
        T D = x_in(4);
        T delta = x_in(5);
        T derD = u_in(0);
        T derDelta = u_in(1);
        const auto ppoly_race_kappa = [&](const T& value) { return callback_race_kappa(p_in, value); };
        const auto ppoly_race_kappa_d1 = [&](const T& value) { return callback_race_kappa_d1(p_in, value); };

        // CSE Intermediate Variables
        T tmp_f0 = 0.5*delta;
        T tmp_f1 = alpha + tmp_f0;
        T tmp_f2 = cos(tmp_f1);
        T tmp_f3 = /* Not supported in C: */
/* ppoly_race_kappa */
ppoly_race_kappa(s);
        T tmp_f4 = n*tmp_f3;
        T tmp_f5 = 1.0 - tmp_f4;
        T tmp_f6 = 1.0/tmp_f5;
        T tmp_f7 = tmp_f2*tmp_f6;
        T tmp_f8 = tmp_f7*v;
        T tmp_f9 = sin(tmp_f1);
        T tmp_f10 = tmp_f9*v;
        T tmp_f11 = 15.5*delta;
        T tmp_f12 = cos(tmp_f0);
        T tmp_f13 = tanh(5.0*v);
        T tmp_f14 = 23.255813953488374*D*(0.28000000000000003 - 0.050000000000000003*v) - 0.2558139534883721*tmp_f13 - 0.13953488372093026*pow(v, 2);
        T tmp_f15 = /* Not supported in C: */
/* ppoly_race_kappa_d1 */
ppoly_race_kappa_d1(s);
        T tmp_f16 = tmp_f2*v;
        T tmp_f17 = tmp_f16/pow(tmp_f5, 2);
        T tmp_f18 = tmp_f15*tmp_f17;
        T tmp_f19 = tmp_f10*tmp_f6;
        T tmp_f20 = 0.5*tmp_f19;

        // Outputs
        fx_out.setZero();
        fu_out.setZero();
        f_out(0) = tmp_f8;
        f_out(1) = tmp_f10;
        f_out(2) = tmp_f11*v - tmp_f3*tmp_f8;
        f_out(3) = tmp_f12*tmp_f14;
        f_out(4) = derD;
        f_out(5) = derDelta;
        fx_out(0,0) = n*tmp_f18;
        fx_out(0,1) = tmp_f17*tmp_f3;
        fx_out(0,2) = -tmp_f19;
        fx_out(0,3) = tmp_f7;
        fx_out(0,5) = -tmp_f20;
        fx_out(1,2) = tmp_f16;
        fx_out(1,3) = tmp_f9;
        fx_out(1,5) = 0.5*tmp_f16;
        fx_out(2,0) = -tmp_f15*tmp_f8 - tmp_f18*tmp_f4;
        fx_out(2,1) = -tmp_f17*pow(tmp_f3, 2);
        fx_out(2,2) = tmp_f19*tmp_f3;
        fx_out(2,3) = tmp_f11 - tmp_f3*tmp_f7;
        fx_out(2,5) = tmp_f20*tmp_f3 + 15.5*v;
        fx_out(3,3) = tmp_f12*(-1.1627906976744187*D + 1.2790697674418605*pow(tmp_f13, 2) - 0.27906976744186052*v - 1.2790697674418605);
        fx_out(3,4) = tmp_f12*(6.5116279069767451 - 1.1627906976744187*v);
        fx_out(3,5) = -0.5*tmp_f14*sin(tmp_f0);
        fu_out(4,0) = 1;
        fu_out(5,1) = 1;
    }


    template <typename T>
    static MSVec<T, NX> rk4_step(
        const MSVec<T, NX>& x,
        const MSVec<T, NU>& u,
        const MSVec<T, NP>& p,
        double dt,
        MSMat<T, NX, NX>* A,
        MSMat<T, NX, NU>* B)
    {
        MSVec<T, NX> k1;
        MSVec<T, NX> k2;
        MSVec<T, NX> k3;
        MSVec<T, NX> k4;
        MSMat<T, NX, NX> fx1;
        MSMat<T, NX, NX> fx2;
        MSMat<T, NX, NX> fx3;
        MSMat<T, NX, NX> fx4;
        MSMat<T, NX, NU> fu1;
        MSMat<T, NX, NU> fu2;
        MSMat<T, NX, NU> fu3;
        MSMat<T, NX, NU> fu4;
        MSMat<T, NX, NX> I;
        MatOps::setIdentity(I);

        continuous_eval(x, u, p, k1, fx1, fu1);
        const MSVec<T, NX> x2 = x + k1 * (0.5 * dt);
        const MSMat<T, NX, NX> dx2_dx = I + fx1 * (0.5 * dt);
        const MSMat<T, NX, NU> dx2_du = fu1 * (0.5 * dt);

        continuous_eval(x2, u, p, k2, fx2, fu2);
        const MSMat<T, NX, NX> dk2_dx = fx2 * dx2_dx;
        const MSMat<T, NX, NU> dk2_du = fx2 * dx2_du + fu2;

        const MSVec<T, NX> x3 = x + k2 * (0.5 * dt);
        const MSMat<T, NX, NX> dx3_dx = I + dk2_dx * (0.5 * dt);
        const MSMat<T, NX, NU> dx3_du = dk2_du * (0.5 * dt);

        continuous_eval(x3, u, p, k3, fx3, fu3);
        const MSMat<T, NX, NX> dk3_dx = fx3 * dx3_dx;
        const MSMat<T, NX, NU> dk3_du = fx3 * dx3_du + fu3;

        const MSVec<T, NX> x4 = x + k3 * dt;
        const MSMat<T, NX, NX> dx4_dx = I + dk3_dx * dt;
        const MSMat<T, NX, NU> dx4_du = dk3_du * dt;

        continuous_eval(x4, u, p, k4, fx4, fu4);
        const MSMat<T, NX, NX> dk4_dx = fx4 * dx4_dx;
        const MSMat<T, NX, NU> dk4_du = fx4 * dx4_du + fu4;

        if (A != nullptr) {
            *A = I + (fx1 + dk2_dx * 2.0 + dk3_dx * 2.0 + dk4_dx) * (dt / 6.0);
        }
        if (B != nullptr) {
            *B = (fu1 + dk2_du * 2.0 + dk3_du * 2.0 + dk4_du) * (dt / 6.0);
        }

        return x + (k1 + k2 * 2.0 + k3 * 2.0 + k4) * (dt / 6.0);
    }


